// The determinism check is mathematically unprovable as stated:
    // When r1.0 == true (forall holds), the ensures clause leaves
    // r1.1 and r2.1 completely unconstrained, so r1 = (true, true)
    // and r2 = (true, false) is a valid counterexample that
    // satisfies the antecedent but falsifies the conclusion.
    // The provable portions follow.
    let ghost forall_expr = forall |i: int| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@;
    let ghost q_expr = self_@[self_.keys@[hi as int]]@ != v@ && (forall |i: int| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@);
    assert((r1.0 == forall_expr && r2.0 == forall_expr) ==> r1.0 == r2.0);
    assert((r1.0 == r2.0 && (!r1.0 ==> r1.1 == q_expr) && (!r2.0 ==> r2.1 == q_expr)) ==> (!r1.0 ==> r1.1 == r2.1));
